SELECT constraint_id, constraint_type, constraint_value
FROM timing_constraints
WHERE circuit_id = 1;

SELECT MAX(slack) AS max_slack
FROM timing_paths
WHERE circuit_id = 1;

SELECT domain_name
FROM clock_domains
WHERE domain_type = 'single' AND domain_frequency = 100.0;

SELECT name, email
FROM designers
ORDER BY name ASC;

SELECT circuit_name
FROM circuits
ORDER BY circuit_name;

SELECT circuit_name
FROM circuits
ORDER BY circuit_name;

SELECT COUNT(*) AS constraint_count
FROM timing_constraints
WHERE constraint_type = 'clock skew';

SELECT DISTINCT d.name
FROM designers d
INNER JOIN circuits c ON d.designer_id = c.designer_id;

SELECT transition_type
FROM signal_transitions
WHERE signal_id = 0;

SELECT circuit_name
FROM circuits
ORDER BY circuit_name;
